scwin.gr_Grid1_oncellclick = async function (rowIndex, columnIndex, columnId) {
  let Row = rowIndex;
  let makeString = "";
  if (ds_Grid1.getCellData(Row, "leaseYn") == "1") {
    makeString = makeString + "LES : Y";
  } else {
    makeString = makeString + "LES : N";
  }
  if (ds_Grid1.getCellData(Row, "socYn") == "1") {
    makeString = makeString + " , SOC : Y";
  } else {
    makeString = makeString + " , SOC : N";
  }
  makeString = makeString + " , TERM : " + ds_Grid1.getCellData(Row, "term");
  if (ds_Grid1.getCellData(Row, "offRtrnClsCd") == "1") {
    makeString = makeString + " , OFF반납 : DOOR반납";
  } else if (ds_Grid1.getCellData(Row, "offRtrnClsCd") == "2") {
    makeString = makeString + " , OFF반납 : CY반납";
  } else if (ds_Grid1.getCellData(Row, "offRtrnClsCd") == "3") {
    makeString = makeString + " , OFF반납 : 부두반납";
  } else {
    makeString = makeString + " , OFF반납 : " + ds_Grid1.getCellData(Row, "offRtrnClsCd");
  }
  makeString = makeString + " , RMK : " + ds_Grid1.getCellData(Row, "rmk");
  // TODO: sp_rmk.innerHTML 대체 → WebSquare textbox setValue 등으로 변환 필요

  if (Row >= 0 && columnId == "cntrTypCd") {
    if (ds_Grid1.getCellData(Row, "cntrTypCd") != "RF") return;
    if (ds_Grid1.getCellData(Row, "cntrNo") == "") {
      await $c.gus.cfAlertMsg($p, "컨테이너번호를 입력하세요.");
      return;
    }
    let url = "/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_05p2.xml";
    await $c.win.openPopup($p, url, {
      width: 300,
      height: 200,
      modal: true,
      data: {}
    });
  } else if (Row >= 0 && columnId == "gridChkBox") {
    if (ds_Grid1.getCellData(Row, "gridChkBox") == "1" || ds_Grid1.getCellData(Row, "gridChkBox") == "T") {
      ds_Grid1.setCellData(Row, "sealNo", ds_Grid1.getCellData(Row, "sealNo").toUpperCase());
      ds_Grid1.setCellData(Row, "cntrNo", ds_Grid1.getCellData(Row, "cntrNo").toUpperCase());
      let now = new Date();
      let year = now.getFullYear();
      let month = ("0" + (now.getMonth() + 1)).slice(-2);
      let day = ("0" + now.getDate()).slice(-2);
      let hour = ("0" + now.getHours()).slice(-2);
      let minute = ("0" + now.getMinutes()).slice(-2);
      let formattedDateTime = year.toString() + month + day + hour + minute;
      if (ds_Grid1.getCellData(Row, "gateoutDth") == "") {
        ds_Grid1.setCellData(Row, "gateoutDth", formattedDateTime);
      }
      scwin.isNotNullGateOutDth = !$c.gus.cfIsNull($p, ds_Grid1.getCellData(Row, "gateOutDth"));
      if (ds_Grid1.getCellData(Row, "chkFlag") == "C") {
        return;
      }
      if (ds_Grid1.getCellData(Row, "cntrNo") == "") {
        await $c.gus.cfAlertMsg($p, "컨테이너번호가 없습니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "vehclNo") == "") {
        await $c.gus.cfAlertMsg($p, "차량번호가 없습니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "chassisNo") == "") {
        if (ds_Grid1.getCellData(Row, "selfSpotClsCd") == "1" || ds_Grid1.getCellData(Row, "selfClsCd") == scwin.SELF_CLS_CD_SELF_CRRYOUT) {} else {
          await $c.gus.cfAlertMsg($p, "샤시 번호가 없습니다.");
          ds_Grid1.setCellData(Row, "gridChkBox", "0");
          return;
        }
      }
      if (ds_Grid1.getCellData(Row, "eqCd") == "") {
        if (ds_Grid1.getCellData(Row, "selfSpotClsCd") == "1" || ds_Grid1.getCellData(Row, "selfClsCd") == scwin.SELF_CLS_CD_SELF_CRRYOUT) {} else {
          await $c.gus.cfAlertMsg($p, "장비코드가 없습니다.");
          ds_Grid1.setCellData(Row, "gridChkBox", "0");
          return;
        }
      }
      if (ds_Grid1.getCellData(Row, "chassisEqCd") == "") {
        if (ds_Grid1.getCellData(Row, "selfSpotClsCd") == "1" || ds_Grid1.getCellData(Row, "selfClsCd") == scwin.SELF_CLS_CD_SELF_CRRYOUT) {} else {
          await $c.gus.cfAlertMsg($p, "샤시장비코드가 없습니다.");
          ds_Grid1.setCellData(Row, "gridChkBox", "0");
          return;
        }
      }
      if (ds_Grid1.getCellData(Row, "arrvlportDtm").length != 12) {
        await $c.gus.cfAlertMsg($p, "입항일시가 없습니다. 또는 유효하지 않은 컨테이너 번호입니다. 컨테이너 번호를 확인하십시요.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if ((ds_Grid1.getCellData(Row, "odrKndCd") == scwin.ODR_KND_CD_EXP_GNRL_CNTR_ODR || ds_Grid1.getCellData(Row, "odrKndCd") == scwin.ODR_KND_CD_EMPTY_POSITION_ODR) && ds_Grid1.getCellData(Row, "dptArvWrkPlClsCd") == scwin.WRK_PL_CLS_CD_DOOR && ds_Grid1.getCellData(Row, "fullEmptyClsCd") == "F") {
        await $c.gus.cfAlertMsg($p, "수출일반 Door운송은 Empty 컨테이너만 반출 가능합니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "cntrTypCd") == scwin.CNTR_TYP_CD_RF && ds_Grid1.getCellData(Row, "dryYn") == "0" && ds_Grid1.getCellData(Row, "temper") == "" && ds_Grid1.getCellData(Row, "fullEmptyClsCd") == "F") {
        await $c.gus.cfAlertMsg($p, "냉동컨테이너 입니다. 온도를 입력하십시요.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "cntrTypCd") == scwin.CNTR_TYP_CD_RF && ds_Grid1.getCellData(Row, "dryYn") == "1" && ds_Grid1.getCellData(Row, "temper") != "") {
        await $c.gus.cfAlertMsg($p, "냉동컨테이너 DRY 입니다. 온도가 입력 되어 있습니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "cmpstcrgKndCd") == scwin.CMPSTCRG_KND_CD_DD && !(ds_Grid1.getCellData(Row, "odrKndCd") == scwin.ODR_KND_CD_IMP_GNRL_CNTR_ODR && ds_Grid1.getCellData(Row, "wrkStpCd") == scwin.WRK_STP_CD_TRANS)) {
        await $c.gus.cfAlertMsg($p, "직도어 복화 입니다. 직도어 복화인 경우 반입화면에서 C4 오더 DOOR 회수만 수행 하시기 바랍니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      dma_searchCustoms.set("mrn", ds_Grid1.getCellData(Row, "mrn"));
      dma_searchCustoms.set("msn", ds_Grid1.getCellData(Row, "msn"));
      dma_searchCustoms.set("hsn", ds_Grid1.getCellData(Row, "hsn"));
      dma_searchCustoms.set("blNo", ds_Grid1.getCellData(Row, "blNo"));
      if (chk_CustomYn.getValue() != "") {
        // TODO: chk_CustomYn uncheck
      } else {
        if (ds_Grid1.getCellData(Row, "odrNo").substring(1, 3) == "C2") {
          if (ed_wrkPlCd.getValue() == "6C01" || ed_wrkPlCd.getValue() == "6C24" || ed_wrkPlCd.getValue() == "6C09" || ed_wrkPlCd.getValue() == "6P10") {
            await $c.sbm.execute($p, sbm_retrieveCustoms);
          }
          if (ds_bondCustom.getRowCount() > 0) {
            if (ds_bondCustom.getCellData(0, "docCd") == "31") {
              if (ds_bondCustom.getCellData(0, "replyAdmitStsCd") != "R") {
                alert("보세운송신고가 아직 수리 되지 않았습니다.");
                ds_Grid1.setCellData(ds_Grid1.getRowPosition(), "gridChkBox", "0");
              }
            }
            if (ds_bondCustom.getCellData(0, "docCd") == "5LH") {
              if (ds_bondCustom.getCellData(0, "replyStsCd") != "1") {
                alert("보세운송정정신고가 접수가 아직 되지 않았습니다.");
              }
            }
            if (ds_bondCustom.getCellData(0, "docCd") == "5CP") {
              if (ds_bondCustom.getCellData(0, "replyStsCd") != "1") {
                alert("보세운송승인신고가 접수가 아직 되지 않았습니다.");
              }
            }
          }
          if (ds_gateCustom.getRowCount() > 0) {
            if (ds_gateCustom.getCellData(0, "docCd") == "1") {
              alert("반출승인내역이 취하되었습니다.");
            }
          }
        }
      }
      scwin.f_retrieveBookingDetail(Row);
      if (scwin.everBookingCheck) {
        scwin.everBookingCheck = false;
        return;
      }

      // TODO: ds_ManagementItem.DataId + Reset 패턴 → submission으로 전환 필요
    }
  }
};
scwin.gr_Grid1_oncelldblclick = function (rowIndex, columnIndex, columnId) {
  let Row = rowIndex;
  if (Row >= 0 && columnId == "odrNo") {
    scwin.f_RetrieveOdrNo();
  } else if (Row >= 0 && columnId == "cntrSizCd") {
    scwin.f_RetrieveCntrNo();
  } else if (Row >= 0 && columnId == "lineCd") {
    if (ds_Grid1.getCellData(Row, "chkFlag") == "C") {
      scwin.f_RetrieveCrryinout();
    }
  } else if (Row >= 0 && (columnId == "pdaCntrNo" || columnId == "pdaSealNo" || columnId == "pdaChassisNo" || columnId == "sealNo")) {
    let pre_cntr = ds_Grid1.getCellData(Row, "cntrNo");
    let pre_chassis = ds_Grid1.getCellData(Row, "chassisNo");
    let pda_cntr = ds_Grid1.getCellData(Row, "pdaCntrNo");
    let pda_chassis = ds_Grid1.getCellData(Row, "pdaChassisNo");
    if (pda_cntr == "") return true;
    scwin.pre_RowPosition = Row;
    if (pre_cntr != pda_cntr) {
      ds_Grid1.setCellData(Row, "cntrNo", ds_Grid1.getCellData(Row, "pdaCntrNo"));
      // TODO: 컨테이너번호 변경 후 조건부 팝업/조회 로직 — 원본 OnDblClick 로직 참조
    }
    if (pre_chassis != pda_chassis) {
      if (pda_chassis == "") return true;
      ds_Grid1.setCellData(Row, "chassisNo", ds_Grid1.getCellData(Row, "pdaChassisNo"));
      scwin.f_chassisSearch("T");
      if (scwin.badChassisNo) ds_Grid1.setCellData(Row, "chassisNo", "");
      if (ds_Grid1.getCellData(Row, "chassisEqCd") == "") {
        ds_Grid1.setCellData(Row, "chassisNo", "");
      }
    }
    ds_Grid1.setCellData(Row, "sealNo", ds_Grid1.getCellData(Row, "pdaSealNo"));
  }
};
scwin.gr_Grid1_ontextimageclick = function (rowIndex, columnIndex, columnId) {
  let row = rowIndex;
  if (columnId == "vehclNo") {
    if (ds_Grid1.getCellData(row, "selfClsCd") == scwin.SELF_CLS_CD_SELF_CRRYOUT) return;
    scwin.f_vehclSearch("T");
  } else if (columnId == "chassisNo") {
    scwin.pre_RowPosition = row;
    scwin.pre_chassisNo = ds_Grid1.getCellData(row, "chassisNo");
    scwin.pre_chassisEqCd = ds_Grid1.getCellData(scwin.pre_RowPosition, "chassisEqCd");
    scwin.f_chassisSearch("F");
  }
};
scwin.f_cntrSearch = function (bCloseFlag) {
  bCloseFlag = bCloseFlag == null ? "T" : bCloseFlag;
  let pClose = "F";
  let odrNoVal = ds_Grid1.getCellData(scwin.pre_RowPosition, "odrNo");
  let wrkPlCdVal = ds_Grid1.getCellData(scwin.pre_RowPosition, "wrkPlCd");
  let cryyinoutIntendNo = ds_Grid1.getCellData(scwin.pre_RowPosition, "crryinoutIntendNo");
  let cntrSizCd = ds_Grid1.getCellData(scwin.pre_RowPosition, "cntrSizCd");
  let cntrTypCd = ds_Grid1.getCellData(scwin.pre_RowPosition, "cntrTypCd");
  let rtnList = $c.gus.cfCommonPopUp($p, "retrieveGateInOutCntrNo", "", "", pClose, null, "컨테이너 No,입항일시,SIZE,TYPE,F/E,COL6,COL7,COL8,COL9,Info", "100,100,60,60,60,10,10,10,10,10", "6,7,8,9,10", odrNoVal + "," + wrkPlCdVal + "," + cryyinoutIntendNo + "," + cntrSizCd + "," + cntrTypCd, null, null, null, null, null, "T", null, null, null);
  if (rtnList == null || rtnList[0][0] == null && rtnList[0] == "N/A") {
    ds_Grid1.setCellData(scwin.pre_RowPosition, "cntrNo", scwin.pre_cntrNo);
    return;
  }
  if (!$c.gus.cfIsNull($p, rtnList)) {
    if (rtnList[0] != "N/A") {
      ds_Grid1.setCellData(scwin.pre_RowPosition, "cntrNo", rtnList[0]);
      // TODO: ds_CntrNoChangeInfo.DataId + Reset 패턴 → submission으로 전환 필요
    }
  }
};
